def turn(disks, start, end):
    if disks[start] == disks[end]:
        return 0
    if disks[start] > disks[end]:
        return 10 - disks[start] + disks[end]
    return disks[end] - disks[start]


def main():
    n = int(input())
    disks = list(map(int, input()))
    target = list(map(int, input()))
    res = 0
    for i in range(n):
        res += min(turn(disks, i, i), turn(disks, i, i + 1))
    print(res)


if __name__ == "__main__":
